import{_ as d,o as e,c as a,ai as r}from"./chunks/framework.bqS7upmD.js";const S=JSON.parse('{"title":"典型业务","description":"","frontmatter":{"title":"典型业务","order":100},"headers":[],"relativePath":"client/web/typical/index.md","filePath":"client/web/typical/index.md"}'),h={name:"client/web/typical/index.md"};function i(o,t,l,n,b,c){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="典型业务" tabindex="-1">典型业务 <a class="header-anchor" href="#典型业务" aria-label="Permalink to “典型业务”">​</a></h1><p>前端开发不仅仅是把设计稿还原成页面，成熟的前端开发者需要独立应对各种交互场景，在用户体验、性能和工程可维护性之间找到平衡。本文档按照场景类别整理了前端 Web 开发中的典型业务场景，每个场景都包含核心问题、技术方案和工程实践。</p><h2 id="交互体验" tabindex="-1">交互体验 <a class="header-anchor" href="#交互体验" aria-label="Permalink to “交互体验”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>核心问题</th><th>关键技术</th></tr></thead><tbody><tr><td>表单处理</td><td>校验规则、动态联动、状态管理</td><td>受控/非受控组件、Schema 校验、多步表单、联动逻辑</td></tr><tr><td>拖拽与排序</td><td>拖拽交互、嵌套排序、跨容器移动</td><td>HTML5 Drag API、指针事件、碰撞检测、动画过渡</td></tr><tr><td>搜索交互</td><td>搜索建议、历史记录、结果高亮</td><td>防抖节流、虚拟列表、Fuse.js/Worker、高亮渲染</td></tr><tr><td>动效与过渡</td><td>页面切换、微交互、性能开销</td><td>CSS Animation、FLIP、View Transitions API、GPU 加速</td></tr></tbody></table><h2 id="数据呈现" tabindex="-1">数据呈现 <a class="header-anchor" href="#数据呈现" aria-label="Permalink to “数据呈现”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>核心问题</th><th>关键技术</th></tr></thead><tbody><tr><td>数据展示</td><td>大列表渲染、图表可视化、实时刷新</td><td>虚拟滚动、Canvas/WebGL、增量更新、轮询与推送</td></tr><tr><td>大屏可视化</td><td>自适应缩放、实时数据、视觉表现</td><td>rem/vw 适配、DataV/ECharts、WebGL 粒子、定时刷新</td></tr><tr><td>3D 可视化</td><td>模型加载、场景交互、渲染性能</td><td>Three.js、WebGPU、LOD 策略、实例化渲染、空间索引</td></tr><tr><td>地图与空间</td><td>坐标系转换、海量标注、路径规划</td><td>Mapbox/高德 JS API、矢量瓦片、WebGL 渲染、空间聚合</td></tr></tbody></table><h2 id="内容创作" tabindex="-1">内容创作 <a class="header-anchor" href="#内容创作" aria-label="Permalink to “内容创作”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>核心问题</th><th>关键技术</th></tr></thead><tbody><tr><td>富文本编辑</td><td>格式控制、内容安全、扩展性</td><td>ProseMirror/Quill、XSS 过滤、粘贴清洗、插件架构</td></tr><tr><td>流程图编辑</td><td>节点连线、布局算法、交互体验</td><td>DAG/Flow 布局、React Flow、贝塞尔曲线、缩放平移</td></tr><tr><td>在线协作编辑</td><td>多人同时编辑、冲突解决、一致性</td><td>OT/CRDT 算法、光标同步、版本历史、离线编辑合并</td></tr><tr><td>低代码平台</td><td>拖拽搭建、组件生态、逻辑编排</td><td>物料引擎、JSON Schema 渲染、属性面板、沙箱隔离</td></tr></tbody></table><h2 id="实时通信" tabindex="-1">实时通信 <a class="header-anchor" href="#实时通信" aria-label="Permalink to “实时通信”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>核心问题</th><th>关键技术</th></tr></thead><tbody><tr><td>WebSocket</td><td>连接管理、断线重连、消息协议</td><td>心跳保活、重连策略、二进制帧、消息队列缓冲</td></tr><tr><td>音视频</td><td>播放控制、实时通话、媒体处理</td><td>WebRTC、Web Audio API、MediaRecorder、HLS/DASH</td></tr><tr><td>消息通知</td><td>实时推送、到达保障、体验优化</td><td>SSE、轮询降级、通知权限、桌面推送、未读计数</td></tr></tbody></table><h2 id="工程能力" tabindex="-1">工程能力 <a class="header-anchor" href="#工程能力" aria-label="Permalink to “工程能力”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>核心问题</th><th>关键技术</th></tr></thead><tbody><tr><td>权限控制</td><td>路由守卫、角色渲染、按钮级控制</td><td>路由拦截、权限指令、动态菜单、RBAC 前端适配</td></tr><tr><td>主题与布局</td><td>深色模式、响应式、动态主题</td><td>CSS 变量、媒体查询、主题切换、容器查询</td></tr><tr><td>国际化</td><td>多语言文案、日期货币、布局适配</td><td>i18n 方案、ICU 格式、RTL 支持、动态加载语言包</td></tr><tr><td>文件处理</td><td>上传进度、断点续传、批量导出</td><td>分片上传、拖拽上传、Blob/Stream、异步导出</td></tr><tr><td>离线与缓存</td><td>弱网可用、资源预载、数据同步</td><td>Service Worker、PWA、IndexedDB、后台同步</td></tr><tr><td>错误与监控</td><td>异常捕获、性能采集、用户行为</td><td>Sentry、Performance API、Source Map、埋点上报</td></tr></tbody></table>',12)])])}const m=d(h,[["render",i]]);export{S as __pageData,m as default};
